#include "softmax_custom_tiling.h"
#include "register/op_def_registry.h"

namespace optiling {

// UB budget: we need 2 tiles (x and exp) plus scalar temporaries.
// Each tile: float => 4 bytes. Two tiles => 8 * tileLen bytes.
static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;  
static constexpr uint32_t ALIGN_ELEMS = 2048;            
static constexpr uint32_t MAX_TILE_ELEMS = 8192;         // avoid too-large tiles

static inline uint32_t AlignDown(uint32_t x, uint32_t a) { return (x / a) * a; }

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    SoftmaxCustomTilingData tiling;

    // Correct API: GetInputShape returns StorageShape*, which has GetOriginShape()
    const gert::StorageShape *storageShape = context->GetInputShape(0);
    const auto &originShape = storageShape->GetOriginShape();
    uint32_t batchSize = static_cast<uint32_t>(originShape.GetDim(0));
    uint32_t dimSize = static_cast<uint32_t>(originShape.GetDim(1));

    // tileLen: number of columns per tile (must not exceed dimSize)
    uint32_t maxTile = UB_BUDGET_BYTES / 8;  // 2 tiles * 4 bytes
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile > MAX_TILE_ELEMS) maxTile = AlignDown(MAX_TILE_ELEMS, ALIGN_ELEMS);
    if (maxTile < ALIGN_ELEMS) maxTile = ALIGN_ELEMS;
    uint32_t tileLen = (dimSize < maxTile) ? dimSize : maxTile;

    // blockDim: each block processes one or more rows; keep between 8 and 24
    uint32_t blockDim = batchSize;
    if (blockDim < 8u) blockDim = 8u;
    if (blockDim > 24u) blockDim = 24u;
    // Ensure at most one row per block for simplicity (but not strictly required)
    if (blockDim > batchSize) blockDim = batchSize;

    context->SetBlockDim(blockDim);

    tiling.set_batchSize(batchSize);
    tiling.set_dimSize(dimSize);
    tiling.set_tileLen(tileLen);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

namespace ge {
static ge::graphStatus InferShape(gert::InferShapeContext *context)
{
    const gert::StorageShape *x_shape = context->GetInputShape(0);
    gert::StorageShape *y_shape = context->GetOutputShape(0);
    *y_shape = *x_shape;
    return GRAPH_SUCCESS;
}

